// Destinatários: diretor + supervisor com 'comparativo313' em agentes.
// Preserva `loja` (string "todas" ou array) — usado no nó de visibilidade.
return items
  .map(it => ({
    json: {
      email_login: (it.json.id || it.json.email_login || '').toLowerCase(),
      nome:        it.json.nome,
      funcao:      it.json.funcao,
      agentes:     it.json.agentes,
      whatsapp:    String(it.json.whatsapp || '').trim(),
      loja:        it.json.loja,
    }
  }))
  .filter(it => {
    const d = it.json;
    return ['diretor', 'supervisor'].includes(d.funcao)
      && Array.isArray(d.agentes) && d.agentes.includes('comparativo313')
      && d.whatsapp && d.whatsapp !== '0' && d.whatsapp.length > 5
      && d.email_login;
  });

// Resolve visibilidade por usuário (igual ao B_metas):
//   - users/{email}.loja = "todas" (string ou item de array) → wildcard
//   - array de strings → filtra por essas filiais
//   - vazio → não vê nada
const usuarios   = $('Filtrar diretor/supervisor').all().map(it => it.json);
const resumoTodo = $('Supabase: resumo todas filiais').all().map(it => it.json);

const SENTINEL = 'todas';
function extraiCod(raw) {
  if (raw == null) return null;
  const s = String(raw).trim();
  if (!s) return null;
  const m = s.match(/^(\d+)/);
  return m ? m[1] : s.toLowerCase();
}
function resolveLojas(lojaRaw) {
  if (typeof lojaRaw === 'string' && lojaRaw.trim().toLowerCase() === SENTINEL) {
    return { wildcard: true, filiais: [] };
  }
  const arr = Array.isArray(lojaRaw)
    ? lojaRaw
    : (lojaRaw == null || lojaRaw === '' ? [] : [lojaRaw]);
  if (arr.some(x => String(x).trim().toLowerCase() === SENTINEL)) {
    return { wildcard: true, filiais: [] };
  }
  const filiais = arr.map(extraiCod).filter(Boolean).filter((v, i, a) => a.indexOf(v) === i);
  return { wildcard: false, filiais };
}

return usuarios.map(u => {
  const { wildcard, filiais } = resolveLojas(u.loja);
  const resumo = wildcard
    ? resumoTodo
    : resumoTodo.filter(r => filiais.includes(String(r.filial_cod)));
  return {
    json: {
      email_login: u.email_login,
      nome:        u.nome,
      whatsapp:    u.whatsapp,
      funcao:      u.funcao,
      wildcard,
      filiais,
      resumo,
    }
  };
});

// Mensagem do diretor/supervisor:
//   - lista TODAS as filiais com ruptura > 0
//   - ordenadas por número de rupturas (desc)
//   - inclui totais consolidados
const u = $input.first().json;

function num(v) {
  if (v == null) return '—';
  return Number(v).toLocaleString('pt-BR', { maximumFractionDigits: 0 });
}

const filiaisComRuptura = (u.resumo || [])
  .filter(r => Number(r.rupturas_pendentes || 0) > 0)
  .sort((a, b) => Number(b.rupturas_pendentes) - Number(a.rupturas_pendentes));

const totalRupturas = filiaisComRuptura.reduce((s, r) => s + Number(r.rupturas_pendentes || 0), 0);
const totalEstoque  = filiaisComRuptura.reduce((s, r) => s + Number(r.estoque_total_deposito || 0), 0);

const linhas = filiaisComRuptura.map(r => {
  const desc = r.filial_desc ? r.filial_desc.replace(/^\d+\s*-\s*/, '') : '';
  return `   • *${r.filial_cod}*${desc ? ' ' + desc : ''} — ${num(r.rupturas_pendentes)} ruptura(s) • ${num(r.estoque_total_deposito)}un no depósito`;
}).join('\n');

const link = $env.APP_URL_COMP313 || 'http://margem.interno/agente/comparativo313';

const message = `Olá, *${u.nome}*!\n\n*Comparativo 313* — produtos faltando nas lojas com estoque no depósito 313:\n\nTotal: *${num(totalRupturas)}* ruptura(s) em ${filiaisComRuptura.length} filial(is) (${num(totalEstoque)} unidades disponíveis no depósito).\n\nQuebra por filial:\n${linhas}\n\nAcesse: ${link}`;

return [{
  json: {
    phone:       u.whatsapp,
    message,
    email_login: u.email_login,
  }
}];
